import{_ as l,o as i,c as o,a2 as t}from"./chunks/framework.Fbjs98zA.js";const m=JSON.parse('{"title":"后端测试规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/08-test.md","filePath":"mango-pmo/rules/backend/08-test.md"}'),a={name:"mango-pmo/rules/backend/08-test.md"};function d(c,e,r,s,n,h){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="后端测试规范" tabindex="-1">后端测试规范 <a class="header-anchor" href="#后端测试规范" aria-label="Permalink to &quot;后端测试规范&quot;">​</a></h1><h2 id="_1-基本要求" tabindex="-1">1. 基本要求 <a class="header-anchor" href="#_1-基本要求" aria-label="Permalink to &quot;1. 基本要求&quot;">​</a></h2><ul><li>有代码改动，必须有对应验证。</li><li>新增业务逻辑，必须补测试。</li><li>修复缺陷，必须补回归测试。</li><li>只写 happy path 不算完成。</li><li>有效测试优先于测试数量；真实行为验证优先于覆盖率数字。</li><li>测试必须验证有风险、有规则、有分支、有副作用或有集成边界的行为。</li></ul><h2 id="_2-测试范围" tabindex="-1">2. 测试范围 <a class="header-anchor" href="#_2-测试范围" aria-label="Permalink to &quot;2. 测试范围&quot;">​</a></h2><p>至少覆盖：</p><ul><li>正常场景</li><li>参数校验</li><li>边界值</li><li>异常场景</li><li>权限或安全约束</li></ul><h2 id="_3-测试目标" tabindex="-1">3. 测试目标 <a class="header-anchor" href="#_3-测试目标" aria-label="Permalink to &quot;3. 测试目标&quot;">​</a></h2><ul><li>每个测试必须能看出测试目标：业务规则、状态变化、异常分支、权限边界、持久化链路、资源注入链路、事务行为、历史回归点等；确属 DTO、getter、常量等机械代码时不应编写测试。</li><li>被测目标必须真实参与执行。</li><li>禁止 mock 被测方法、被测类或本次改动要证明可用的核心路径。</li><li>mock 只能替换测试目标之外的协作者。</li><li>测试结论不能超过真实覆盖范围；mock 了数据库结果，就不能声称验证了 SQL、Mapper、事务或数据库链路。</li><li>实现路径迁移必须验证迁移后的真实路径；例如 JDBC 改 Mapper，验收测试必须让 Mapper、SQL 映射和数据库读写真实参与。</li></ul><h2 id="_4-测试层次" tabindex="-1">4. 测试层次 <a class="header-anchor" href="#_4-测试层次" aria-label="Permalink to &quot;4. 测试层次&quot;">​</a></h2><ul><li>单元测试：验证纯业务规则、复杂分支、状态机、校验器、转换规则和异常路径。</li><li>组件测试：验证模块内多个类的协作，可以替换外部系统，但模块内核心链路应真实参与。</li><li>集成测试：验证模块协作、数据库、Mapper、事务、Spring 装配、接口契约、资源注入和权限过滤。</li><li>E2E 测试：验证 app/API/安全过滤器/跨模块主流程，可以替换第三方外部服务，但不能替换 Mango 内部主链路。</li><li>E2E 测试脚本必须独立、完整、可组合执行；用例不能依赖隐式执行顺序、上一个用例残留状态或人工预置数据。</li><li>E2E 测试必须能按单个用例、按标签/能力组合、按全量套件执行，并保持相同断言口径。</li><li>后端 E2E 使用 JUnit 5 <code>@Tag</code> 标识组合维度，至少包含 <code>e2e</code> 和能力标签，例如 <code>auth</code>、<code>workflow</code>、<code>payment</code>；涉及慢测或外部依赖时额外标记 <code>slow</code> 或 <code>external</code>。</li><li>E2E 用例必须自行创建依赖数据或调用明确 fixture，使用唯一测试数据标识，并在前置或后置步骤清理自身数据。</li><li>禁止 E2E 使用 <code>@TestMethodOrder</code> 表达业务依赖，禁止跨用例共享可变静态业务状态，禁止用例 A 创建数据供用例 B 验收。</li><li>后端 E2E 最小验证入口应覆盖单用例、能力标签和全量套件；无法执行任一组合时，交付记录必须说明阻塞原因和风险。</li><li>只做有效测试：测行为、规则、边界、链路，不测 DTO、getter/setter、常量、简单透传、机械装配。</li><li>不要求每次都写 E2E。</li><li>是否需要前端或 E2E 测试，按需求影响面决定。</li></ul><h2 id="_5-分层归属" tabindex="-1">5. 分层归属 <a class="header-anchor" href="#_5-分层归属" aria-label="Permalink to &quot;5. 分层归属&quot;">​</a></h2><ul><li>测试资产目录归属遵循 <code>mango-pmo/rules/04-test-assets.md</code>。</li><li><code>common</code>：测试放各模块 <code>src/test/java</code>，只测公共规则、通用工具、SPI 契约和高复用基础逻辑，以 <code>UnitTest</code> 为主。</li><li><code>infra</code>：模块内 <code>src/test/java</code> 只放少量复杂局部逻辑测试；跨 <code>api/support/core/starter/starter-remote</code> 的能力链路、单体真实链路、多服务协作链路统一放 <code>mango-infra-test</code>。</li><li><code>platform</code>：测试放各模块 <code>src/test/java</code>，主要验证业务规则、command/query/usecase/service 链路和模块内部协作，以 <code>IntegrationTest</code> 为主。</li><li><code>app</code>：测试放各 app 模块 <code>src/test/java</code>，主要验证端到端业务流程和关键用户主链路，以 <code>E2ETest</code> 为主。</li></ul><h2 id="_6-要测与不测" tabindex="-1">6. 要测与不测 <a class="header-anchor" href="#_6-要测与不测" aria-label="Permalink to &quot;6. 要测与不测&quot;">​</a></h2><ul><li>要测：行为分支、状态变化、参数校验、边界值、异常场景、权限或安全约束、并发风险、远程调用/注册/转发、多实现一致性、历史回归点。</li><li>不测：DTO、record、getter/setter、常量类、简单 constructor、简单 controller 透传、简单 delegation wrapper、只有 bean 存在与否的机械装配测试。</li><li>禁止为了覆盖率、测试数量或形式完整性编写无价值测试。</li><li>禁止写实现复述式测试，例如声明简单变量或固定返回值后只断言它等于自身预期值。</li></ul><h2 id="_7-mock-与测试替身" tabindex="-1">7. Mock 与测试替身 <a class="header-anchor" href="#_7-mock-与测试替身" aria-label="Permalink to &quot;7. Mock 与测试替身&quot;">​</a></h2><ul><li>mock、stub、fake、spy 只能用于隔离测试目标之外的协作者。</li><li>允许用测试替身模拟第三方支付、短信、企业微信、远程 HTTP 服务等外部系统。</li><li>允许用测试替身注入超时、网络失败、第三方错误码、重试失败等难以稳定复现的异常和边界。</li><li>允许在纯单元测试中替换与当前测试目标无关的旁路依赖。</li><li>禁止用 mock 覆盖真实集成问题。</li><li>禁止 mock 数据库、Mapper、权限、资源注入或工作流关键结果后，声称测试覆盖了真实数据库、权限、资源注入或工作流链路。</li><li>只验证调用次数的 mock 测试不能作为业务行为正确的验收依据。</li><li>保留 Mockito 等测试替身时，必须能说明测试目标、真实参与验证的对象和替身替换的边界。</li></ul><h2 id="_8-数据库测试隔离" tabindex="-1">8. 数据库测试隔离 <a class="header-anchor" href="#_8-数据库测试隔离" aria-label="Permalink to &quot;8. 数据库测试隔离&quot;">​</a></h2><ul><li>禁止自动化测试连接 dev、stage、prod 或共享业务库写入数据。</li><li>不得为了避免脏数据而 mock 数据库、Mapper 或持久化结果；需要验证持久化链路时，必须使用隔离测试库、嵌入式数据库或容器数据库。</li><li>每个会写库的测试必须自行准备依赖数据，不依赖人工预置数据、其它用例残留数据或隐式执行顺序。</li><li>每个会写库的测试必须具备清理策略：事务回滚、<code>BeforeEach</code> 清表、<code>AfterEach</code> 删除测试数据、销毁容器或销毁一次性 schema。</li><li>Spring service/mapper 集成测试优先使用 <code>@Transactional</code> 自动回滚；不适合回滚的异步、跨线程、消息、调度或 E2E 测试必须显式清理自身数据。</li><li>测试数据必须可识别，推荐使用 <code>TEST_</code>、<code>IT_</code>、<code>E2E_</code> 加能力或 issue 编号作为前缀；批量数据必须带唯一业务键，便于定位和清理。</li><li>测试清理只能清理本测试创建的数据或隔离测试库内的数据；禁止在共享库上执行无条件 <code>truncate</code>、全表 <code>delete</code> 或破坏性初始化。</li><li>E2E 测试必须使用专用测试库、专用测试租户或专用测试账号；用例必须独立创建数据，并在前置或后置步骤清理自身数据。</li></ul><h2 id="_9-数据库物料选择" tabindex="-1">9. 数据库物料选择 <a class="header-anchor" href="#_9-数据库物料选择" aria-label="Permalink to &quot;9. 数据库物料选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐物料</th><th>口径</th></tr></thead><tbody><tr><td>纯业务规则、转换、校验、状态机</td><td>无数据库单元测试</td><td>覆盖规则和分支，不声称覆盖持久化</td></tr><tr><td>MyBatis-Plus 基础 CRUD、Wrapper 条件、字段映射</td><td>H2 <code>MODE=MySQL</code></td><td>覆盖基础 Mapper 和表字段映射，不声称覆盖 MySQL 专有行为</td></tr><tr><td>MySQL JSON、复杂 SQL、索引、锁、事务隔离、方言函数</td><td>Testcontainers MySQL 或专用 MySQL 测试库</td><td>覆盖真实 MySQL 行为</td></tr><tr><td>Spring service 持久化链路</td><td>H2 或 Testcontainers，加真实 Mapper 和事务管理</td><td>覆盖 service 到 mapper 到数据库链路</td></tr><tr><td>resource handler 资源注入落库</td><td>H2 或 Testcontainers，加真实目标 Mapper</td><td>覆盖资源声明解析和落库链路</td></tr><tr><td>异步、消息、调度、跨线程</td><td>隔离测试库加唯一测试数据和显式清理</td><td>覆盖异步副作用，不能依赖事务回滚</td></tr><tr><td>app/API/E2E 主流程</td><td>专用测试库、测试租户、测试账号</td><td>覆盖跨模块主链路和清理能力</td></tr></tbody></table><h2 id="_10-命名规则" tabindex="-1">10. 命名规则 <a class="header-anchor" href="#_10-命名规则" aria-label="Permalink to &quot;10. 命名规则&quot;">​</a></h2><ul><li>测试类名使用 <code>XxxTest</code>。</li><li>测试方法名使用 <code>方法_场景_结果</code>。</li><li>推荐用意图区分测试层次：<code>*UnitTest</code>、<code>*IntegrationTest</code>、<code>*E2ETest</code>。</li><li>测试类名如果以实现类型开头，测试物料必须和类名一致： <ul><li><code>RedisXxxTest</code> 必须使用 Redis 实现或真实 Redis 集成物料。</li><li><code>JdbcXxxTest</code> 必须使用 JDBC 实现和数据库物料。</li><li><code>MemoryXxxTest</code> 必须使用 Memory 实现。</li></ul></li><li>通用能力或契约测试不要以实现类型命名，应按能力命名，例如 <code>CacheTest</code>、<code>LockerTest</code>、<code>RateLimiterTest</code>。</li><li>同一能力需要覆盖多个实现时，使用参数化测试或明确的 fixture 注入，每个参数必须能看出实际实现类型。</li></ul><h2 id="_11-测试物料" tabindex="-1">11. 测试物料 <a class="header-anchor" href="#_11-测试物料" aria-label="Permalink to &quot;11. 测试物料&quot;">​</a></h2><ul><li>测试名声称验证 Redis/JDBC/Memory 时，不得用其他实现替代核心被测物料。</li><li>mock、stub 只能用于隔离外部协作者，不能替代被测实现本身。</li><li>集成测试必须使用真实集成物料或等价容器/嵌入式环境；无法运行时必须在交付记录说明跳过原因。</li><li>能力测试应验证能力语义，不只验证一次方法返回值；至少覆盖成功、拒绝或失败、key 隔离、TTL/窗口、非法参数。</li></ul><h2 id="_12-存量-mockito-治理" tabindex="-1">12. 存量 Mockito 治理 <a class="header-anchor" href="#_12-存量-mockito-治理" aria-label="Permalink to &quot;12. 存量 Mockito 治理&quot;">​</a></h2><ul><li>存量 Mockito 测试不一刀切删除，先按测试目标和替身边界分类。</li><li><code>KEEP</code>：测试目标清楚，mock 只替换目标之外的协作者。</li><li><code>MIGRATE</code>：mock 掉被测核心链路，必须改为真实集成测试或组件测试。</li><li><code>REWRITE</code>：测试有价值但断言、物料或测试结构错误。</li><li><code>DELETE</code>：只测常量、字段赋值、调用次数，或完全复述实现。</li><li>每个存量 Mockito 测试至少回答：测试目标是什么、被测目标是否真实执行、mock 是否替换了关键验收链路。</li></ul><h2 id="_13-提交前检查" tabindex="-1">13. 提交前检查 <a class="header-anchor" href="#_13-提交前检查" aria-label="Permalink to &quot;13. 提交前检查&quot;">​</a></h2><p>至少执行与改动范围对应的检查：</p><ul><li><code>mvn test</code></li><li><code>mvn verify</code></li><li><code>mvn pmd:check</code></li><li><code>mvn checkstyle:check</code></li><li><code>mvn mango:check</code></li><li>涉及 KV、缓存、锁、限流、幂等、token、id 等能力时，执行 <code>mvn mango:check -Drule=test-fixture</code></li><li>修改后端测试或新增 Mockito/test double 时，执行 <code>node mango-pmo/tools/audit-backend-test-mocks.mjs --report-only --changed-only --base origin/main</code> 并说明新增风险。</li></ul><h2 id="_14-交付要求" tabindex="-1">14. 交付要求 <a class="header-anchor" href="#_14-交付要求" aria-label="Permalink to &quot;14. 交付要求&quot;">​</a></h2><ul><li>功能可运行</li><li>测试通过</li><li>验证结果可说明</li><li>说明测试覆盖了哪些实现物料，哪些实现因环境原因未执行</li><li>说明关键测试的目标、真实参与验证的链路和使用 mock 的边界。</li></ul><h2 id="_15-禁止事项" tabindex="-1">15. 禁止事项 <a class="header-anchor" href="#_15-禁止事项" aria-label="Permalink to &quot;15. 禁止事项&quot;">​</a></h2><ul><li>不写测试直接提交业务改动</li><li>用 mock 覆盖真实集成问题</li><li>mock 被测目标或本次改动要证明可用的核心链路</li><li>用无价值单元测试冒充有效验证</li><li>发现回归后不补测试</li><li>自动化测试向共享业务库写入脏数据</li><li>为了避免脏数据而跳过真实持久化链路验证</li><li><code>RedisXxxTest</code> 内实际使用 <code>MemoryKvStore</code>、<code>JdbcKvStore</code> 等错配物料</li><li><code>JdbcXxxTest</code> 内实际使用 <code>MemoryKvStore</code>、<code>RedisKvStore</code> 等错配物料</li><li>为了让测试通过而降低测试名、断言或物料真实性</li></ul>',33)])])}const p=l(a,[["render",d]]);export{m as __pageData,p as default};
